import{_ as a,c as n,a as e,o as i}from"./app-CEcM0piI.js";const l={};function p(d,s){return i(),n("div",null,s[0]||(s[0]=[e(`<p>is用于判断（断言） as用于转换（类型转换）</p><p>和java一样除了基础数据类型外,数组,字符串以及自定义的类型都是引用数据类型</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>Form f1;</span></span>
<span class="line"><span>Form f2;</span></span>
<span class="line"><span>f1=new Form;</span></span>
<span class="line"><span>f2=f1</span></span>
<span class="line"><span>f1.SetTitle(&quot;form1&quot;);</span></span>
<span class="line"><span>f2.show();    //输出结果为form1</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="类的三大成员" tabindex="-1"><a class="header-anchor" href="#类的三大成员"><span>类的三大成员</span></a></h2><p>与其他语言不同,C#的类中的成员除了属性(property)和方法(method)外还多了一个事件(event)</p><h3 id="成员" tabindex="-1"><a class="header-anchor" href="#成员"><span>成员</span></a></h3><ol><li>静态（Static）成员在语义上表示它是&quot;类的成员’</li><li>实例（非静态）成员在语义表示它是&quot;对象的成员</li><li>绑定（Binding）指的是编译器如果把一个成员与类或对象关联起来</li></ol><h3 id="事件" tabindex="-1"><a class="header-anchor" href="#事件"><span>事件</span></a></h3><p>类或对象通知其它类或对象的机制，为C#所特有（其他语言通过其它办法实现这个机制）</p><h1 id="访问权限" tabindex="-1"><a class="header-anchor" href="#访问权限"><span>访问权限</span></a></h1><ul><li>public：所有对象都可以访问；</li><li>private：对象本身在对象内部可以访问；</li><li>protected：只有该类对象及其子类对象可以访问</li><li>internal：同一个程序集的对象可以访问；(只能在当前项目中访问)</li><li>protected internal：访问限于当前程序集或派生自包含类的类型。</li></ul><p>protected权限是可以继承的,即使是在另一个项目中只要继承了对应的类也是可以访问的 internal只能在当前项目中访问 如果在同一个项目中internal权限比protected大,如果在另外的项目中protected权限更大</p><p>比如说：一个人A为父类，他的儿子B，妻子C，私生子D（注：D不在他家里）</p><p>如果我们给A的事情增加修饰符：</p><ul><li>public事件，地球人都知道，全公开</li><li>protected事件，A，B，D知道（A和他的所有儿子知道，妻子C不知道）</li><li>private事件，只有A知道（隐私？心事？）</li><li>internal事件，A，B，C知道（A家里人都知道，私生子D不知道）</li><li>protected internal事件，A，B，C，D都知道,其它人不知道</li></ul><p><strong>使用权限修饰符修饰声明类时,子类的访问权限不能高于父类的访问权限,如果违法会暴露父类中的属性</strong></p><h1 id="类-vs-结构" tabindex="-1"><a class="header-anchor" href="#类-vs-结构"><span>类 vs 结构</span></a></h1><p>类和结构在设计和使用时有不同的考虑因素，类适合表示复杂的对象和行为，支持继承和多态性，而结构则更适合表示轻量级数据和值类型，以提高性能并避免引用的管理开销。</p><p>类和结构有以下几个基本的不同点：</p><p><strong>值类型 vs 引用类型：</strong></p><ul><li><strong>结构是值类型（Value Type）：</strong> 结构是值类型，它们在栈上分配内存，而不是在堆上。当将结构实例传递给方法或赋值给另一个变量时，将复制整个结构的内容。</li><li><strong>类是引用类型（Reference Type）：</strong> 类是引用类型，它们在堆上分配内存。当将类实例传递给方法或赋值给另一个变量时，实际上是传递引用（内存地址）而不是整个对象的副本。</li></ul><p><strong>继承和多态性：</strong></p><ul><li><strong>结构不能继承：</strong> 结构不能继承其他结构或类，也不能作为其他结构或类的基类。</li><li><strong>类支持继承：</strong> 类支持继承和多态性，可以通过派生新类来扩展现有类的功能。</li></ul><p><strong>默认构造函数：</strong></p><ul><li><strong>结构不能有无参数的构造函数：</strong> 结构不能包含无参数的构造函数。每个结构都必须有至少一个有参数的构造函数。</li><li><strong>类可以有无参数的构造函数：</strong> 类可以包含无参数的构造函数，如果没有提供构造函数，系统会提供默认的无参数构造函数。</li></ul><p><strong>赋值行为：</strong></p><ul><li>类型为类的变量在赋值时存储的是引用，因此两个变量指向同一个对象。</li><li>结构变量在赋值时会复制整个结构，因此每个变量都有自己的独立副本。</li></ul><p><strong>传递方式：</strong></p><ul><li>类型为类的对象在方法调用时通过引用传递，这意味着在方法中对对象所做的更改会影响到原始对象。</li><li>结构对象通常通过值传递，这意味着传递的是结构的副本，而不是原始结构对象本身。因此，在方法中对结构所做的更改不会影响到原始对象。</li></ul><p><strong>可空性：</strong></p><p>结构体是值类型，不能直接设置为 null：因为 null 是引用类型的默认值，而不是值类型的默认值。如果你需要表示结构体变量的缺失或无效状态，可以使用 Nullable&lt;\\T&gt; 或称为 T? 的可空类型。 类默认可为null：类的实例默认可以为 <code>null</code>，因为它们是引用类型。</p><p><strong>性能和内存分配</strong></p><p>结构通常更轻量： 由于结构是值类型且在栈上分配内存，它们通常比类更轻量，适用于简单的数据表示。 类可能有更多开销： 由于类是引用类型，可能涉及更多的内存开销和管理。</p><h1 id="继承" tabindex="-1"><a class="header-anchor" href="#继承"><span>继承</span></a></h1><p>和java一样一个类只能继承一个类能继承多个接口</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>class A{}</span></span>
<span class="line"><span>class B : A{}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="接口" tabindex="-1"><a class="header-anchor" href="#接口"><span>接口</span></a></h3><p><code>interface</code>声明</p><h3 id="属性" tabindex="-1"><a class="header-anchor" href="#属性"><span>属性</span></a></h3><p>属性赋值get,set方法</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>class Person{</span></span>
<span class="line"><span>	string _name;</span></span>
<span class="line"><span>	string Name{</span></span>
<span class="line"><span>		get{return _name;}</span></span>
<span class="line"><span>		set{_name=value;}</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Person p;</span></span>
<span class="line"><span>p.Name=&quot;tom&quot;;</span></span>
<span class="line"><span>Console.WriteLine(p.Name);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>其中Name依旧是一个属性,不过作为中间过渡了,给他赋值就会会调用其中地set方法给_name属性赋值 在这样的函数和正常的函数一样</p><h3 id="this和base" tabindex="-1"><a class="header-anchor" href="#this和base"><span>this和base</span></a></h3><p>this可以实现委托构造</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>class Person{</span></span>
<span class="line"><span>	string name;</span></span>
<span class="line"><span>	int age;</span></span>
<span class="line"><span>	Person(string name,int age,int money){</span></span>
<span class="line"><span>		this.name=name;</span></span>
<span class="line"><span>		this.age=age;</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>	Person(string name):this(&quot;tom&quot;,16){}</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>base和this用法一样,它表示的是当前类的基类指针</p><h1 id="装箱和拆箱" tabindex="-1"><a class="header-anchor" href="#装箱和拆箱"><span>装箱和拆箱</span></a></h1><p>装箱: 将值类型转换为引用类型 拆箱: 将引用类型转换为值类型</p><p>要出现装箱和拆箱必须满足两个类是继承关系,如果不是继承关系一定不是装箱和拆箱</p><p>在程序中应尽量避免装箱和拆箱,这会损耗性能</p><h1 id="多态" tabindex="-1"><a class="header-anchor" href="#多态"><span>多态</span></a></h1><h2 id="虚函数" tabindex="-1"><a class="header-anchor" href="#虚函数"><span>虚函数</span></a></h2><p>在函数前加上virtual关键字声明虚函数</p><p>自己在重写父类的虚函数时需要在函数前加上override关键字表示重写虚函数</p><h2 id="抽象类" tabindex="-1"><a class="header-anchor" href="#抽象类"><span>抽象类</span></a></h2><p>在类名前使用abstract关键字声明当前类是抽象类 在函数前使用abstract关键字声明表示当前函数是抽象函数</p><h3 id="抽象属性" tabindex="-1"><a class="header-anchor" href="#抽象属性"><span>抽象属性</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>abstract class Person{</span></span>
<span class="line"><span>	abstract string Name{</span></span>
<span class="line"><span>		set;</span></span>
<span class="line"><span>		get;</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="接口-1" tabindex="-1"><a class="header-anchor" href="#接口-1"><span>接口</span></a></h2><p>使用interface关键字定义 接口中的成员不允许添加权限修饰符默认都是public 一个类同时继承类和实现接口,那么重写语法必须先实现类的</p><h3 id="显式实现接口" tabindex="-1"><a class="header-anchor" href="#显式实现接口"><span>显式实现接口</span></a></h3><p>显式实现接口是为了解决函数重名问题</p><div class="language- line-numbers-mode has-collapsed-lines collapsed" data-highlighter="shiki" data-ext="" style="--vp-collapsed-lines:15;--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>    interface IFly</span></span>
<span class="line"><span>    {</span></span>
<span class="line"><span>      void fly();</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    class Bird : IFly</span></span>
<span class="line"><span>    {</span></span>
<span class="line"><span>      public void fly()</span></span>
<span class="line"><span>      {</span></span>
<span class="line"><span>        Console.WriteLine(&quot;鸟类的飞&quot;);</span></span>
<span class="line"><span>      }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>      void IFly.fly()</span></span>
<span class="line"><span>      {</span></span>
<span class="line"><span>        Console.WriteLine(&quot;IFly接口的飞&quot;);</span></span>
<span class="line"><span>      }</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    static void Main(string[] args)</span></span>
<span class="line"><span>    {</span></span>
<span class="line"><span>      Bird bird = new Bird();</span></span>
<span class="line"><span>      bird.fly();</span></span>
<span class="line"><span>      IFly fly = bird;</span></span>
<span class="line"><span>      fly.fly();</span></span>
<span class="line"><span>    }</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div><div class="collapsed-lines"></div></div><h1 id="部分类" tabindex="-1"><a class="header-anchor" href="#部分类"><span>部分类</span></a></h1><p>通常来说在同一个项目中不允许有重名的类,这样会报错 但是在多人协作的场景下可能会需要多人共同写一个类的情况,这种情况就可以定义部分类</p><p>部分类表示一个类的一部分,在相同的部分类中可以只要是定义在部分类中的内容在其他部分类中都是共享的</p><p>部分类声明使用partial关键字</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>partial class Person{</span></span>
<span class="line"><span>	string _name;</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>partial class Person{</span></span>
<span class="line"><span>	void test(){</span></span>
<span class="line"><span>		Console.WriteLine(_name);</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="密封类" tabindex="-1"><a class="header-anchor" href="#密封类"><span>密封类</span></a></h1><p>密封类不可以被继承,声明使用sealed关键字</p><h1 id="tostring" tabindex="-1"><a class="header-anchor" href="#tostring"><span>ToString</span></a></h1><p>在C#中所有类默认都有一个ToString函数,它默认是返回当前类所在的命名空间和类名 可以重写ToString函数</p><h1 id="泛型" tabindex="-1"><a class="header-anchor" href="#泛型"><span>泛型</span></a></h1><p>自定义泛型直接在(函数,类,接口)名后面写上尖括号和占位符即可</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>class Person&lt;T&gt;{}</span></span>
<span class="line"><span>void test&lt;T&gt;(){}</span></span>
<span class="line"><span>interface able&lt;T&gt;{}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="泛型约束" tabindex="-1"><a class="header-anchor" href="#泛型约束"><span>泛型约束</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>public class MyClass&lt;T, K, V, W, X, Y, Z&gt;</span></span>
<span class="line"><span>	where T : struct    //约束r必须是值类型</span></span>
<span class="line"><span>	where K : class    //约束k必须是引用类型。</span></span>
<span class="line"><span>	where V : IComparable    //约束V必须实现了IComparable接口</span></span>
<span class="line"><span>	where W : K    //要求w必须是k类型那个或者k类型的子类</span></span>
<span class="line"><span>	where X : class,new()//对于一个类型有多个约束必须使用&quot;逗号隔开&quot;，当有多个类型约束与new一起使用时，new()约束必须写在最后。</span></span>
<span class="line"><span>{}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="匿名函数" tabindex="-1"><a class="header-anchor" href="#匿名函数"><span>匿名函数</span></a></h1><p>定义匿名函数</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>delegate(int a){}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>有返回值的匿名函数不用显式声明返回值,直接返回即可</p><p>lambda表达式的声明和js的一样</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>()=&gt;{}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h1 id="反射" tabindex="-1"><a class="header-anchor" href="#反射"><span>反射</span></a></h1><p>只有程序集才可以反射.dll文件,相当于java的字节码,可以可反射java的字节码 程序集和c语言的dll动态库不一样</p><p><strong>获取一个对象的类型</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>Person p=new Person();</span></span>
<span class="line"><span>Type type1=p.GetType();</span></span>
<span class="line"><span>Type type2=typeof(Person);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>使用GetType函数可以获取一个对象的类型,通过typeof函数可以获取一个类的类型</p><p>通过Type类型可以访问类中的很多成员</p><p><strong>获取一个类型的父类</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>Type type3=type1.BaseType;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>通过BaseType函数可以获取一个类型的父类,返回的是一个type类型</p><p><strong>获取一个类型的字段</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>FieldInfo[] fields=type1.GetFields();</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>获取一个类型中具有访问权限的字段,返回的是一个数组类型,受保护的字段无法获取</p><h3 id="获取动态库中的类型" tabindex="-1"><a class="header-anchor" href="#获取动态库中的类型"><span>获取动态库中的类型</span></a></h3><p>程序集也叫做动态库</p><p>加载动态库</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>Assembly asm=Assembly.LoadFile(@&quot;path&quot;);</span></span>
<span class="line"><span>Type[] types=asm.GetTypes();</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>GetTypes获取程序集中的所有类型</p><p><strong>获取所有public类型</strong> GetExportedTypes()获取所有public类型,返回的是一个Type数组</p><p><strong>检查某个对象是否是指定类型</strong> IsInstanceOfType</p><p>验证类的关系与接口无关</p><p><strong>通过反射调用函数</strong> 获取到反射中的函数要调用时需要指定调用者也就是反射类型的实例,和参数列表,参数列表是一个object的数组,如果没有可以用null指针代替</p><p>要获取到反射中的私有成员需要使用<code>BindingFlags.NonPublic | BindingFlags.Instance</code>枚举值</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>MethodInfo method=type1.GetMethod(&quot;函数名&quot;,BindingFlags.NonPublic | BindingFlags.Instance);</span></span>
<span class="line"><span>method.Invoke(Activator.CreateInstance(type1),null);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>获取到函数后要调用还需要将反射类型实例化并传入参数</p><h3 id="标志枚举" tabindex="-1"><a class="header-anchor" href="#标志枚举"><span>标志枚举</span></a></h3><p>BindingFlags是一个标志枚举 标志枚举和普通枚举不同的是,普通枚举是互斥的,标志枚举是可以共存的</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>enum flag{</span></span>
<span class="line"><span>	A,</span></span>
<span class="line"><span>	B,</span></span>
<span class="line"><span>	C</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[flags]</span></span>
<span class="line"><span>enum flags{</span></span>
<span class="line"><span>	A=1,</span></span>
<span class="line"><span>	b=2,</span></span>
<span class="line"><span>	c=4</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>标记枚举可以使用flags标记, 通过手动指定数,这样它们相或的时候二进制位上就不会冲突</p><h1 id="索引器" tabindex="-1"><a class="header-anchor" href="#索引器"><span>索引器</span></a></h1><p>索引器：让对象可以像数组一样使用索引访问其中元素，让程序看起来更直观 语法：权限修饰符 返回值 this[形参列表]{ get； set； } 相当于重载了[]</p>`,113)]))}const r=a(l,[["render",p]]),c=JSON.parse('{"path":"/game/cs/2/","title":"2 类和对象","lang":"zh-CN","frontmatter":{"title":"2 类和对象","createTime":"2025/04/05 12:12:26","permalink":"/game/cs/2/"},"readingTime":{"minutes":9.24,"words":2771},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/游戏/C#/2 类和对象.md","headers":[]}');export{r as comp,c as data};
